import React, { useState, useEffect } from 'react';
import {
  Grid,
  Card,
  CardContent,
  CardMedia,
  Typography,
  CardActions,
  Button,
  Box,
  Chip,
  CircularProgress,
  Alert,
  Container
} from '@mui/material';
import { api } from '../services/api';

const Certificates = ({ featured = false }) => {
  const [certificates, setCertificates] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchCertificates = async () => {
      try {
        const response = await api.get(`/certificates${featured ? '?featured=true' : ''}`);
        const data = response.data;
        setCertificates(
          Array.isArray(data)
            ? data
            : data.items || data.data || []
        );
        setLoading(false);
      } catch (err) {
        setError('Failed to fetch certificates');
        setLoading(false);
      }
    };
    fetchCertificates();
  }, [featured]);

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" my={4}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>;
  }

  return (
    <Container maxWidth="lg" sx={{ py: 6 }}>
      <Typography
        variant="h3"
        component="h2"
        align="center"
        gutterBottom
        sx={{ fontWeight: 800, letterSpacing: 1, color: 'primary.main', mb: 6 }}
      >
        Certificates
      </Typography>
      <Grid container spacing={5}>
        {certificates.map((certificate) => (
          <Grid item key={certificate._id} xs={12} sm={6} md={4}>
            <Card
              elevation={8}
              sx={{
                borderRadius: 5,
                background: 'linear-gradient(135deg, #f4f7fa 0%, #e0e7ef 100%)',
                boxShadow: '0 4px 24px 0 rgba(60, 72, 88, 0.10)',
                display: 'flex',
                flexDirection: 'column',
                minHeight: 420,
              }}
            >
              {certificate.imageUrl && (
                <CardMedia
                  component="img"
                  height="180"
                  image={certificate.imageUrl}
                  alt={certificate.title}
                  sx={{ objectFit: 'cover', borderTopLeftRadius: 20, borderTopRightRadius: 20 }}
                />
              )}
              <CardContent sx={{ flexGrow: 1 }}>
                <Typography gutterBottom variant="h5" component="h3" sx={{ fontWeight: 700, color: 'primary.main' }}>
                  {certificate.title}
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                  {certificate.issuer}
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                  Issued: {certificate.issueDate ? new Date(certificate.issueDate).toLocaleDateString() : ''}
                </Typography>
                <Box sx={{ mt: 2, mb: 1 }}>
                  {Array.isArray(certificate.skills) && certificate.skills.map((skill) => (
                    <Chip
                      key={skill}
                      label={skill}
                      size="small"
                      sx={{ mr: 1, mb: 1, fontWeight: 600, background: '#e0e7ef', color: 'primary.main' }}
                    />
                  ))}
                </Box>
              </CardContent>
              <CardActions sx={{ justifyContent: 'flex-end', px: 2, pb: 2 }}>
                {certificate.credentialUrl && (
                  <Button
                    size="small"
                    color="primary"
                    variant="outlined"
                    href={certificate.credentialUrl}
                    target="_blank"
                    sx={{ borderRadius: 8, fontWeight: 600 }}
                  >
                    View Certificate
                  </Button>
                )}
              </CardActions>
            </Card>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
};

export default Certificates;
